import { z } from 'zod';
import api from '../app/client';

import type { Role } from '../../types/role';
import type { User } from '../../types/user';
import { RoleSchema, PaginatedSchema, UserSchema } from '../../types/schemas';

export type { Role };

export interface RolesParams {
  pageIndex?: number;
  pageSize?: number;
  sort?: string;
  sortOrder?: 'Ascending' | 'Descending';
  search?: string;
  active?: boolean;
}

const PaginatedRoleSchema = PaginatedSchema(RoleSchema);

export const roleService = {
  getRoles: (params?: RolesParams) =>
    api.get('/roles', { params }).then(r => PaginatedRoleSchema.parse(r.data)),

  getRoleById: (id: string) =>
    api.get(`/roles/${id}`).then(r => r.data),

  createRole: (data: Record<string, unknown>) =>
    api.post('/roles', data).then(r => r.data),

  updateRole: (id: string, data: Record<string, unknown>) =>
    api.put(`/roles/${id}`, data).then(r => r.data),

  deleteRole: (id: string) =>
    api.delete(`/roles/${id}`).then(r => r.data),

  getRoleUsers: (roleId: string): Promise<User[]> =>
    api.get(`/roles/${roleId}/users`).then(r => {
      const data = Array.isArray(r.data) ? r.data : (r.data?.data ?? []);
      return z.array(UserSchema).parse(data);
    }),

  getRolePermissions: (roleId: string) =>
    api.get(`/roles/${roleId}/permissions`).then(r => r.data),

  setRolePermissions: (roleId: string, assignments: Array<{ permissionId: string; isGranted: boolean }>) =>
    api.put(`/roles/${roleId}/permissions`, { assignments }).then(r => r.data),

  addUsersToRole: (roleId: string, userIds: string[]) =>
    api.post(`/roles/${roleId}/users`, { userIds }),

  removeUserFromRole: (roleId: string, userId: string) =>
    api.delete(`/roles/${roleId}/users/${userId}`),
};
